const trades = $input.all().map(i => i.json);
const wh = $('Webhook').first().json;
return [{ json: { trades, sheet_id: wh.body.sheet_id, email: wh.body.email || '' } }];

// Construir config desde filas campo/valor
const configRows = $input.all().map(i => i.json || {});
const trades = $('Preparar Datos').first().json.trades || [];

function escapeHtml(value) {
  return String(value ?? '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#39;');
}

function parseNumber(value) {
  if (value === null || value === undefined) return NaN;
  const s = String(value).trim().toUpperCase();
  if (!s) return NaN;
  if (s === 'BE') return 0;
  const normalized = s.replace('%', '').replace(/\s/g, '').replace(',', '.').replace('+', '');
  const n = parseFloat(normalized);
  return Number.isFinite(n) ? n : NaN;
}

// Leer config de forma robusta
const config = {};
for (const row of configRows) {
  const entries = Object.entries(row);
  const lowerRow = Object.fromEntries(entries.map(([k, v]) => [String(k).toLowerCase(), v]));
  const campo = lowerRow.campo ?? lowerRow.field ?? Object.values(row)[0];
  const valor = lowerRow.valor ?? lowerRow.value ?? Object.values(row)[1];
  if (campo && valor !== undefined) {
    config[String(campo).trim().toLowerCase()] = valor;
  }
  for (const [k, v] of Object.entries(lowerRow)) {
    if (v !== undefined && v !== null && String(v).trim() !== '') {
      if (!config[k]) config[k] = v;
    }
  }
}

const mes = String(config.mes || 'MES').toUpperCase();
const anio = String(config.anio || new Date().getFullYear());

// Calcular total
const computedTotal = trades.reduce((acc, t) => {
  const resultado = t.resultado ?? t.Resultado ?? '';
  const n = parseNumber(resultado);
  return acc + (Number.isFinite(n) ? n : 0);
}, 0);

let totalRaw = config.total;
if (totalRaw === undefined || totalRaw === null || String(totalRaw).trim() === '' || String(totalRaw).trim().toLowerCase() === 'total') {
  totalRaw = `${computedTotal >= 0 ? '+' : ''}${computedTotal.toFixed(2)}%`;
}
const total = String(totalRaw);

// Ajustes dinámicos según cantidad de trades
const rowCount = trades.length;
let titleSize = 52;
let bodySize = 16;
let rowPaddingY = 9;
let headerMargin = 24;
let totalSize = 22;
let logoHeight = 34;

if (rowCount > 18) {
  titleSize = 46;
  bodySize = 14;
  rowPaddingY = 7;
  headerMargin = 18;
  totalSize = 20;
  logoHeight = 30;
}
if (rowCount > 24) {
  titleSize = 40;
  bodySize = 12;
  rowPaddingY = 5;
  headerMargin = 14;
  totalSize = 18;
  logoHeight = 28;
}

const logoUrl = 'https://raw.githubusercontent.com/Dtolosag/M71/main/assets/logo-m71.png';

const logoHtml = logoUrl
  ? `<div class="logo-sec"><img src="${logoUrl}" alt="M71 Trading" onerror="this.parentElement.style.display='none'"></div>`
  : '';

// Generar filas
const rowsHtml = trades.map(t => {
  const fecha = escapeHtml(t.fecha ?? t.Fecha ?? '');
  const activo = escapeHtml(t.activo ?? t.Activo ?? '');
  const tipo = escapeHtml(t.tipo ?? t.Tipo ?? '');
  const resultado = escapeHtml(t.resultado ?? t.Resultado ?? '');

  const rawResultado = String(t.resultado ?? t.Resultado ?? '').trim().toUpperCase();
  const n = parseNumber(resultado);
  let resultColor;
  if (rawResultado === 'BE') {
    resultColor = '#ff9500';
  } else if (Number.isFinite(n) && n < 0) {
    resultColor = '#ff4040';
  } else {
    resultColor = '#3dff50';
  }

  return `<tr>
    <td>${fecha}</td>
    <td>${activo}</td>
    <td>${tipo}</td>
    <td style="color:${resultColor}">${resultado}</td>
  </tr>`;
}).join('\n');

const html = `<!DOCTYPE html>
<html lang="es">
<head>
<meta charset="UTF-8">

<style>
*, *::before, *::after { box-sizing: border-box; }

@page {
  size: auto;
  margin: 0;
}

html, body {
  margin: 0;
  padding: 0;
  background: #0d0d0d;
  color: #ffffff;
  font-family: Arial Black, Impact, 'Arial Narrow', Arial, sans-serif;
  -webkit-print-color-adjust: exact;
  print-color-adjust: exact;
}

body { width: 100%; }

.page {
  width: 100%;
  background: #0d0d0d;
  padding: 30px 34px 24px;
}

.logo-sec {
  text-align: center;
  margin-bottom: 12px;
}

.logo-sec img {
  height: ${logoHeight}px;
}

.header {
  text-align: center;
  margin-bottom: ${headerMargin}px;
}

.t1, .t2 {
  display: block;
  font-weight: 900;
  text-transform: uppercase;
  letter-spacing: 2px;
  line-height: 0.95;
  font-size: ${titleSize}px;
}

.t1 { color: #ffffff; }
.t2 { color: #3dff50; }

table {
  width: 100%;
  border-collapse: collapse;
  table-layout: fixed;
}

colgroup col:nth-child(1) { width: 20%; }
colgroup col:nth-child(2) { width: 28%; }
colgroup col:nth-child(3) { width: 30%; }
colgroup col:nth-child(4) { width: 22%; }

thead tr {
  background: #1a1a1a;
  border-bottom: 2px solid #3dff50;
}

thead th {
  font-size: ${bodySize - 2}px;
  font-weight: 900;
  text-transform: uppercase;
  letter-spacing: 1px;
  color: #ffffff;
  padding: ${rowPaddingY + 2}px 10px;
  text-align: center;
}

tbody tr {
  border-bottom: 1px solid #1e1e1e;
}

tbody tr:nth-child(even) {
  background: #111111;
}

tbody td {
  font-size: ${bodySize}px;
  font-weight: 700;
  color: #ffffff;
  padding: ${rowPaddingY}px 10px;
  text-align: center;
}

.total-row {
  margin-top: 12px;
  text-align: center;
  font-size: ${totalSize}px;
  font-weight: 900;
  text-transform: uppercase;
  letter-spacing: 1px;
  color: #ffffff;
  padding: 14px 0 6px;
  border-top: 2px solid #3dff50;
}

.total-row span {
  color: #3dff50;
}
</style>
</head>
<body>
<div class="page">
  ${logoHtml}
  <div class="header">
    <span class="t1">Resultados</span>
    <span class="t2">${mes} ${anio}</span>
  </div>
  <table>
    <colgroup>
      <col /><col /><col /><col />
    </colgroup>
    <thead>
      <tr>
        <th>Fecha</th>
        <th>Activo Operado</th>
        <th>Tipo de Operacion</th>
        <th>Resultado (%)</th>
      </tr>
    </thead>
    <tbody>
      ${rowsHtml}
    </tbody>
  </table>
  <div class="total-row">Total ${mes}: <span>${escapeHtml(total)}</span></div>
</div>
</body>
</html>`;

const binaryData = await this.helpers.prepareBinaryData(
  Buffer.from(html, 'utf-8'),
  'index.html',
  'text/html'
);

// Calcular alto aproximado de página en pulgadas
// Header ~120px, row ~38px, total ~60px, padding ~60px. A 96dpi
const approxHeightPx = 120 + (rowCount * 38) + 60 + 60 + (logoUrl ? 60 : 0);
const approxHeightIn = (approxHeightPx / 96).toFixed(3);

return [{ json: { mes, anio, total, rowCount, paperHeight: approxHeightIn }, binary: { htmlFile: binaryData } }];

const pdf = $input.first().binary.pdfData;

return [
  {
    json: {},
    binary: {
      data: pdf
    }
  }
];
